    private void Update(FormTemplate form, CustomerAllFormTemplateDto dto)
    {
        var dtoRoleIds = dto.Roles.ToHashSet();

        foreach (var role in form.Roles.ToList())
        {
            if (!dtoRoleIds.Contains(role.RoleId))
                context.FormRoles.Remove(role);
        }

        var formRoleIds = form.Roles.Select(x => x.RoleId).ToHashSet();
        foreach (var roleId in dto.Roles)
        {
            if (!formRoleIds.Contains(roleId))
                form.Roles.Add(new FormRole { RoleId = roleId });
        }

        var fieldsById = form.Fields.ToDictionary(x => x.Id);

        // Locked fields must keep local state (including IsActive); only unlockable fields are deactivated then refreshed from Admin.
        foreach (var field in form.Fields)
        {
            if (!field.Locked)
                field.IsActive = false;
        }

        // Parents / groups first so relationship remap can resolve within the same form.
        var orderedFields = dto.Fields
            .OrderBy(x => x.ParentFieldId.HasValue)
            .ThenBy(x => x.GroupId.HasValue)
            .ToList();

        foreach (var c in orderedFields)
        {
            if (!fieldsById.TryGetValue(c.Id, out var formField))
            {
                formField = new FormField { Id = c.Id };
                form.Fields.Add(formField);
            }

            if (!formField.Locked)
                c.Adapt(formField);

            fieldsById[formField.Id] = formField;
        }

        RemapFieldRelationships(form.Fields, fieldsById);
    }

    /// <summary>
    /// Relinks <see cref="FormField.ParentField"/> and <see cref="FormField.GroupParent"/> using Ids from the sync payload.
    /// Clears orphan FKs instead of throwing when a referenced field is missing from this form.
    /// </summary>
    private static void RemapFieldRelationships(
        IList<FormField> fields,
        IReadOnlyDictionary<int, FormField> fieldsById)
    {
        foreach (var field in fields)
        {
            if (field.ParentFieldId.HasValue)
            {
                if (fieldsById.TryGetValue(field.ParentFieldId.Value, out var parent))
                    field.ParentField = parent;
                else
                {
                    field.ParentFieldId = null;
                    field.ParentField = null!;
                }
            }

            if (field.GroupId.HasValue)
            {
                if (fieldsById.TryGetValue(field.GroupId.Value, out var group))
                    field.GroupParent = group;
                else
                {
                    field.GroupId = null;
                    field.GroupParent = null!;
                }
            }
        }
    }
}

