    private async Task<bool> SyncFiles(HttpClient httpClient, CancellationToken cancellationToken)
    {
        try
        {
            FormTemplateFilesQuery query = new();
            var res = await _sender.Send(query, cancellationToken);

            if (!res.IsSuccess)
            {
                AddError("خطا در خواندن لیست فایل‌ها");
                return false;
            }

            var reportPath = _options.Value.ReportPath;
            if (!Directory.Exists(reportPath))
                Directory.CreateDirectory(reportPath);

            var fileNames = res.Value.Result;
            if (fileNames.Count == 0)
                return true;

            var syncOptions = _syncOptions.Value;
            var parallelism = Math.Max(1, syncOptions.FileDownloadParallelism);
            using var gate = new SemaphoreSlim(parallelism, parallelism);

            int downloaded = 0;
            int skipped = 0;
            int failed = 0;
            var failureSamples = new List<string>();

            var tasks = fileNames.Select(async fileName =>
            {
                await gate.WaitAsync(cancellationToken);
                try
                {
                    var fileUrl = BuildReportFileUrl(fileName);
                    var filePath = Path.Combine(reportPath, fileName);

                    var parentDir = Path.GetDirectoryName(filePath);
                    if (!string.IsNullOrEmpty(parentDir) && !Directory.Exists(parentDir))
                        Directory.CreateDirectory(parentDir);

                    if (syncOptions.SkipUnchangedFiles
                        && await ShouldSkipFileDownloadAsync(httpClient, fileUrl, filePath, cancellationToken))
                    {
                        Interlocked.Increment(ref skipped);
                        return;
                    }

                    var downloadError = await DownloadFileWithRetryAsync(
                        httpClient,
                        fileUrl,
                        filePath,
                        syncOptions,
                        cancellationToken);

                    if (downloadError is null)
                    {
                        Interlocked.Increment(ref downloaded);
                        return;
                    }

                    Interlocked.Increment(ref failed);
                    lock (failureSamples)
                    {
                        if (failureSamples.Count < 5)
                            failureSamples.Add($"{fileName}: {downloadError}");
                    }
                }
                catch (Exception ex) when (ex is not OperationCanceledException)
                {
                    Interlocked.Increment(ref failed);
                    lock (failureSamples)
                    {
                        if (failureSamples.Count < 5)
                            failureSamples.Add($"{fileName}: {ex.Message}");
                    }
                }
                finally
                {
                    gate.Release();
                }
            });

            await Task.WhenAll(tasks);

            _logger.LogInformation(
                "File sync finished. Downloaded: {Downloaded}, skipped unchanged: {Skipped}, failed: {Failed}, total listed: {Total}.",
                downloaded,
                skipped,
                failed,
                fileNames.Count);

            if (failed > 0)
            {
                var sample = failureSamples.Count == 0
                    ? string.Empty
                    : " نمونه: " + string.Join(" | ", failureSamples);
                AddError($"خطا در بارگیری {failed} از {fileNames.Count} فایل گزارش.{sample}");
            }

            return true;
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            AddError($"خطای غیرمنتظره در همگام‌سازی فایل‌ها: {ex.Message}");
            return false;
        }
    }

    private string BuildReportFileUrl(string fileName)
    {
        var reportUrl = _options.Value.ReportUrl.TrimEnd('/');
        var encodedName = string.Join(
            '/',
            fileName.Split('/', StringSplitOptions.RemoveEmptyEntries)
                .Select(Uri.EscapeDataString));
        return $"{reportUrl}/{encodedName}";
    }

    private static async Task<string?> DownloadFileWithRetryAsync(
        HttpClient httpClient,
        string fileUrl,
        string filePath,
        SyncOption syncOptions,
        CancellationToken cancellationToken)
    {
        var maxAttempts = Math.Max(1, syncOptions.FileDownloadMaxRetries);
        var delayMs = Math.Max(100, syncOptions.FileDownloadRetryDelayMs);
        string? lastError = null;

        for (var attempt = 1; attempt <= maxAttempts; attempt++)
        {
            cancellationToken.ThrowIfCancellationRequested();

            using var response = await httpClient.GetAsync(
                fileUrl,
                HttpCompletionOption.ResponseHeadersRead,
                cancellationToken);

            if (response.IsSuccessStatusCode)
            {
                await using var fileStream = new FileStream(
                    filePath,
                    FileMode.Create,
                    FileAccess.Write,
                    FileShare.None);
                await response.Content.CopyToAsync(fileStream, cancellationToken);
                return null;
            }

            lastError = $"کد وضعیت {response.StatusCode}";
            if (!IsTransientStatus(response.StatusCode) || attempt == maxAttempts)
                return lastError;

            await Task.Delay(TimeSpan.FromMilliseconds(delayMs * attempt), cancellationToken);
        }

        return lastError;
    }

    private static bool IsTransientStatus(System.Net.HttpStatusCode statusCode)
        => statusCode is System.Net.HttpStatusCode.RequestTimeout
            or System.Net.HttpStatusCode.TooManyRequests
            or System.Net.HttpStatusCode.ServiceUnavailable
            or System.Net.HttpStatusCode.GatewayTimeout;

    private static async Task<bool> ShouldSkipFileDownloadAsync(
        HttpClient httpClient,
        string fileUrl,
        string filePath,
        CancellationToken cancellationToken)
